import { useEffect, useState } from "react";
import { Footer } from "./Footer";
import { NavBarRecepcionar } from "./NavBarRecepcionar";
import pattern from "../slike/pattern4.jpg";

export function RezervacijeRecepcionar() {
  const [rezervacije, setRezervacije] = useState([]);
  const [filterStatus, setFilterStatus] = useState("ALL");

  useEffect(() => {
    fetch("http://localhost:8080/reservations/all")
      .then((res) => res.json())
      .then((data) => {
        if (data?.data?.values) setRezervacije(data.data.values);
      })
      .catch((err) => console.error("Greška pri učitavanju rezervacija:", err));
  }, []);

  const filtriraneRezervacije = filterStatus === "ALL"
    ? rezervacije
    : rezervacije.filter(r => r.statusRezervacije === filterStatus);

  const handleStatusChange = async (rez, noviStatus) => {
    await fetch("http://localhost:8080/reservations/update", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ...rez, statusRezervacije: noviStatus }),
    });
    setRezervacije(prev =>
      prev.map(r => r.idRezervacija === rez.idRezervacija ? { ...r, statusRezervacije: noviStatus } : r)
    );
  };

  return (
    <div>
      <NavBarRecepcionar />
      <h2>Sve rezervacije</h2>
      
      <label>Filtriraj po statusu:</label>
      <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)}>
        <option value="ALL">Sve</option>
        <option value="PENDING">Na čekanju</option>
        <option value="CONFIRMED">Potvrđene</option>
        <option value="CANCELLED">Otkazane</option>
      </select>

      <div style={{ display: "flex", flexWrap: "wrap", gap: "20px", marginTop: "20px" }}>
        {filtriraneRezervacije.map(r => (
          <div key={r.idRezervacija} style={{ background: "#fff", padding: "15px", borderRadius: "10px" }}>
            <h3>{r.soba?.naziv || "Nepoznata soba"}</h3>
            <p>Status: {r.statusRezervacije}</p>
            <p>Datum prijave: {r.datumPrijave}</p>
            <p>Datum odjave: {r.datumOdjave}</p>

            <button onClick={() => handleStatusChange(r, "CONFIRMED")}>✅ Potvrdi</button>
            <button onClick={() => handleStatusChange(r, "CANCELLED")}>❌ Odbij</button>
          </div>
        ))}
      </div>
      <Footer />
    </div>
  );
}
